sql:
SELECT COUNT(*)
FROM outputs
WHERE transaction_id = 20958;

SELECT block_id, average_fee, transaction_count
FROM transaction_stats
GROUP BY block_id;

SELECT blocks.block_id, miners.miner_name 
FROM blocks 
INNER JOIN miners ON blocks.block_miner = miners.miner_name;

SELECT block_hash, difficulty, block_miner
FROM blocks
WHERE total_fee = (SELECT MAX(total_fee) FROM blocks);

SELECT metric_name, metric_value
FROM network_health
WHERE health_id = 1;

SELECT b.block_id, ts.transaction_count AS total_transactions
FROM blocks AS b
JOIN transaction_stats AS ts ON b.block_id = ts.block_id;

SELECT transaction_id
FROM fees
WHERE fee_amount > (SELECT AVG(fee_amount) FROM fees);

SELECT block_hash
FROM blocks
WHERE total_fee = (SELECT MAX(total_fee) FROM blocks);

SELECT miner_name, total_rewards
FROM miners
WHERE total_rewards = (
    SELECT MAX(total_rewards)
    FROM miners
);

SELECT COUNT(*) AS active_alerts
FROM alerts
WHERE status = 'active';

SELECT AVG(total_fee)
FROM blocks
WHERE difficulty > (SELECT AVG(difficulty) FROM blocks);

SELECT witness_id, transaction_id, signature, public_key, witness_type
FROM witnesses
WHERE witness_id = 1;
